import path from 'node:path';
import { fileURLToPath } from 'node:url';

import { build } from 'esbuild';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const repoRoot = path.resolve(__dirname, '..');

const entryFile = path.join(repoRoot, 'monitoring/shared/pq.source.js');
const browserOutputFile = path.join(repoRoot, 'monitoring/shared/pq.js');
const moduleOutputFile = path.join(repoRoot, 'monitoring/shared/pq.mjs');
const banner = {
    js: '// Generated by npm run build-wallet-pq. Do not edit this file directly.',
};

await build({
    entryPoints: [entryFile],
    outfile: browserOutputFile,
    bundle: true,
    format: 'iife',
    platform: 'browser',
    target: ['es2022'],
    sourcemap: false,
    logLevel: 'info',
    banner,
});

await build({
    entryPoints: [entryFile],
    outfile: moduleOutputFile,
    bundle: true,
    format: 'esm',
    platform: 'browser',
    target: ['es2022'],
    sourcemap: false,
    logLevel: 'info',
    banner,
});